class Node:
 def __init__(self, value):
 self.value = value
 self.next = None

class LinkedList:
 def __init__(self):
 self.head = None

 def append(self, value):
 node = Node(value)
 if self.head is None:
 self.head = node
 else:
 current = self.head
 while current.next is not None:
 current = current.next
 current.next = node

# Example usage:
linked_list = LinkedList()
linked_list.append(1)
linked_list.append(2)
linked_list.append(3)
